function fetchApiCnpjBuscaDadosComIE(cnpj) {

  return fetch(`https://publica.cnpj.ws/cnpj/${cnpj}`)
}

async function fetchApiCnpjVerificaExistencia(cnpj) {
  var statusRequest;
  let data = await fetch(`https://minhareceita.org/${cnpj}`);

  if (data.status == 200) {
    data = await data.json();
    statusRequest = { status: 200, data, api: "API-minhareceita" };

    return statusRequest;

  } else {
    return await fetchApiCnpjRedundancia(cnpj)
  }
}

async function fetchApiCnpjBuscaDadosRedundancia(cnpj) {
  var statusRequest;
  await $.ajax({
    url: `https://www.receitaws.com.br/v1/cnpj/${cnpj}`,
    dataType: 'jsonp',
    type: 'GET'
  }).always((data, textStatus) => {
    data.status != 'ERROR' ? statusRequest = { status: 200, data, api: "API-receitaws" } : statusRequest = { status: "CNPJ Não Encontrado" };
  });

  return statusRequest;
}

function fetchApiCepBuscaDadosEndereco(cep) {

  return fetch(`https://viacep.com.br/ws/${cep}/json/`)
}

async function PreencheEnderecoComCepForn(cep) {

  try {
    let dados_json = await fetchApiCepBuscaDadosEndereco(cep)
    let dados_obj = await dados_json.json()

    $("#bairroforn").val(dados_obj.bairro)
    $("#cidadeforn").val(dados_obj.localidade)
    $("#ufforn").val(dados_obj.uf)
    $("#nibgeforn").val(dados_obj.ibge)

  }
  catch (e) {
    console.log("Erro ao retornar o autocomplete pelo CEP " + e.message)

  }

}

async function preencheDadosFornecedorComAPI(cnpjNaoFormatado, dadosAlternativosForn) {
  $("#resultadocadfornecedor .alert").remove()

  var cnpjFormatado = cnpjNaoFormatado.replace(/\D/g, "");
  let dados_json = await fetchApiCnpjBuscaDadosComIE(cnpjFormatado);

  if (dados_json.status == 200) {
    console.log("API-publicaws")

    var dadosFornecedor = await dados_json.json()
    var inscricaoEstadualForn = dadosFornecedor['estabelecimento']['inscricoes_estaduais'][0] ? dadosFornecedor['estabelecimento']['inscricoes_estaduais'][0]['inscricao_estadual'] : "";
    var razaoForn = dadosFornecedor['razao_social'] ? dadosFornecedor['razao_social'] : "";
    var fantasiaForn = dadosFornecedor['estabelecimento']['nome_fantasia'] ? dadosFornecedor['estabelecimento']['nome_fantasia'] : razaoForn;
    var cepForn = dadosFornecedor['estabelecimento']['cep'] ? dadosFornecedor['estabelecimento']['cep'].replace('-', '').replace('.', '') : "";
    var enderecoForn = dadosFornecedor['estabelecimento']['logradouro'] ? dadosFornecedor['estabelecimento']['logradouro'] : "";
    var numeroEnderecoForn = dadosFornecedor['estabelecimento']['numero'] ? dadosFornecedor['estabelecimento']['numero'] : "";
    var complementoForn = dadosFornecedor['estabelecimento']['complemento'] ? dadosFornecedor['estabelecimento']['complemento'] : "";
    var emailForn = dadosFornecedor['estabelecimento']['email'] ? dadosFornecedor['estabelecimento']['email'] : "";
    var tel1Forn = dadosFornecedor['estabelecimento']['ddd1'] + dadosFornecedor['estabelecimento']['telefone1'] ? dadosFornecedor['estabelecimento']['ddd1'] + dadosFornecedor['estabelecimento']['telefone1'] : "";

    $("#inscestadualforn").val(inscricaoEstadualForn);
    $("#razaoforn").val(razaoForn);
    $("#fantasiaforn").val(fantasiaForn);
    $("#cepforn").val(cepForn);
    $("#enderecoforn").val(enderecoForn);
    $("#numeroendforn").val(numeroEnderecoForn);
    $("#complementoendforn").val(complementoForn);
    $("#emailforn").val(emailForn);
    $("#tel1forn").val(tel1Forn);

    PreencheEnderecoComCepForn($("#cepforn").val().replace(/\D/g, ""));

    return true
  } else {
    console.log(dadosAlternativosForn.api)

    emailForn = dadosAlternativosForn.data.email ? dadosAlternativosForn.data.email : "";
    cepForn = dadosAlternativosForn.data.cep ? dadosAlternativosForn.data.cep.replace(/\D/g, "") : "";
    enderecoForn = dadosAlternativosForn.data.logradouro ? dadosAlternativosForn.data.logradouro : "";
    numeroEnderecoForn = dadosAlternativosForn.data.numero ? dadosAlternativosForn.data.numero : "";
    complementoForn = dadosAlternativosForn.data.complemento ? dadosAlternativosForn.data.complemento : "";

    if (dadosAlternativosForn.api == "receitaws") {
      razaoForn = dadosAlternativosForn.data.nome ? dadosAlternativosForn.data.nome : "";
      fantasiaForn = dadosAlternativosForn.data.fantasia ? dadosAlternativosForn.data.fantasia : razaoForn;
      tel1Forn = dadosAlternativosForn.data.telefone ? (dadosAlternativosForn.data.telefone.split('/'))[0].replace(/\D/g, "") : "";

    } else {
      razaoForn = dadosAlternativosForn.data["razao_social"] ? dadosAlternativosForn.data["razao_social"] : "";
      fantasiaForn = dadosAlternativosForn.data["nome_fantasia"] ? dadosAlternativosForn.data["nome_fantasia"] : razaoForn;
      tel1Forn = dadosAlternativosForn.data["ddd_telefone"] ? dadosAlternativosForn.data["ddd_telefone"].replace(/\D/g, "") : "";

    }

    $("#razaoforn").val(razaoForn);
    $("#fantasiaforn").val(fantasiaForn);
    $("#cepforn").val(cepForn);
    $("#enderecoforn").val(enderecoForn);
    $("#numeroendforn").val(numeroEnderecoForn);
    $("#complementoendforn").val(complementoForn);
    $("#emailforn").val(emailForn);
    $("#tel1forn").val(tel1Forn);

    PreencheEnderecoComCepForn($("#cepforn").val().replace(/\D/g, ""))

    return true;
  }
}

function modal_Preenchimento_CNPJ(cnpjFornecedor) {
  var cnpjFornecedorFormatado = cnpjFornecedor ? cnpjFornecedor.replace(/\D/g, "") : "";

  Swal.fire({
    title: 'Deseja Autocompletar ou Atualizar as Informações deste Fornecedor Automaticamente?',
    showCancelButton: true,
    confirmButtonColor: '#3085d6',
    cancelButtonColor: '#d33',
    confirmButtonText: 'Sim',
    cancelButtonText: 'Não'
  }).then(async (result) => {

    if (result.value == true & cnpjFornecedorFormatado !== "" & cnpjFornecedorFormatado.length == 14) {
      let dadosFornAPI = await fetchApiCnpjVerificaExistencia(cnpjFornecedorFormatado);
      let status = dadosFornAPI.status;
      var dadosAlternativosForn = dadosFornAPI;

      if (status === 200) {

        Swal.fire({
          title: "Carregando os dados do CNPJ... Por favor aguarde!",
          type: "info",
          html: ``,
          allowOutsideClick: false,
          allowEscapeKey: false,
          timer: 5000,
          onOpen: async function () {

            Swal.showLoading()

            let status_preenchimento = await preencheDadosFornecedorComAPI(cnpjFornecedorFormatado, dadosAlternativosForn);

            if (status_preenchimento) {

              Swal.fire({
                title: 'Dados Preenchidos com Sucesso!',
                type: 'success',
                timer: 3000
              })
            } else {

              Swal.fire({
                title: 'Erro ao preencher os dados, aguarde 1 minuto e tente novamente ou faça o preenchimento manual!',
                type: 'error'
              })
            }

          }
        }).then((resultTimer) => {

          if (resultTimer.dismiss == 'timer') {
            Swal.fire({
              title: 'Tempo de Carregamento Excedido, Tente Novamente Mais Tarde ou Faça o Preenchimento Manual!',
              type: 'error'
            })
          }
        })

      } else if (status !== 200) {
        Swal.fire({
          title: `${status} ou CNPJ Inválido!`,
          text: `Favor Digitar um CNPJ Válido ou Faça o Preenchimento Manual!`,
          type: 'warning'
        })

      }

    } else if (result.value == true & cnpjFornecedorFormatado.length < 14 & cnpjFornecedorFormatado !== '') {
      Swal.fire({
        title: `CNPJ Incompleto! ${14 - cnpjFornecedorFormatado.length == 1 ? `Falta ${14 - cnpjFornecedorFormatado.length} Digito, Favor Verificar o CNPJ!` : `Faltam ${14 - cnpjFornecedorFormatado.length} Digitos, Favor Verificar o CNPJ!`}`,
        type: 'warning'
      })

    } else if (result.value == true & !cnpjFornecedorFormatado) {
      Swal.fire({
        title: `CNPJ Vazio!`,
        text: `Favor Digitar o CNPJ!`,
        type: 'error'
      })

    }
  })

}

