function retornoListaVincFabForn(respostaListaVincFabForn) {

  var idFornecedor = $("#idfornselect").val();
  var idFab = $("#idfabselect").val();
  var stativoVinc = 'True';

  if (respostaListaVincFabForn.data.length != 0) {
    for (var i = 0; i < respostaListaVincFabForn.data.length; i++) {
      contador++;
      var registro = respostaListaVincFabForn.data[i];

      idForVinc = registro.IDFORNECEDOR;
      idFabVinc = registro.IDFABRICANTE;
      idVincFabFor = registro.IDFABRICANTEFORN;
      DsFornVinc = registro.NOFANTFORN;
      DsFabVinc = registro.DSFABRICANTE;

      if (idForVinc == idFornecedor && idFabVinc == idFab) {
        Swal.fire({
          type: "warning",
          title: "Fabricante e Fornecedor já Vinculados! ",
          showConfirmButton: false,
          timer: 2000
        });
      } else {
        var dadosVincFabForn = [{
          "IDFABRICANTE": parseInt(idFab),
          "IDFORNECEDOR": parseInt(idFornecedor),
          "STATIVO": stativoVinc
        }];

        ajaxPost("api/compras/fabricante-fornecedor.xsjs", dadosVincFabForn)
          .then(funcSucessVincFabFor)
          .catch(funcError);

      }
    }
  } else {
    var dadosVincFabForn = [{
      "IDFABRICANTE": parseInt(idFab),
      "IDFORNECEDOR": parseInt(idFornecedor),
      "STATIVO": stativoVinc
    }];

    ajaxPost("api/compras/fabricante-fornecedor.xsjs", dadosVincFabForn)
      .then(funcSucessVincFabFor)
      .catch(funcError);

  }
}

