async function PreencheEnderecoComCepTransportadora(cep) {

  try {
    let dados_json = await fetchApiCepBuscaDadosEndereco(cep)
    let dados_obj = await dados_json.json()

    $("#bairrotransp").val(dados_obj.bairro)
    $("#cidadetransp").val(dados_obj.localidade)
    $("#uftransp").val(dados_obj.uf)
    $("#nibgetransp").val(dados_obj.ibge)

  }
  catch (e) {
    console.log("Erro ao retornar o autocomplete pelo CEP " + e)

  }

}

async function preencheDadosTransportadoraComAPI(cnpjNaoFormatado, dadosAlternativosTransp) {

  $("#resultadocadtransportador .alert").remove()

  var cnpjFormatado = cnpjNaoFormatado.replace(/\D/g, "")
  let dados_json = await fetchApiCnpjBuscaDadosComIE(cnpjFormatado)

  if (dados_json.status == 200) {
    console.log("publicaws")

    var dadosTransportadora = await dados_json.json()
    var inscricaoEstadualTransp = dadosTransportadora['estabelecimento']['inscricoes_estaduais'].length ? dadosTransportadora['estabelecimento']['inscricoes_estaduais'][0]['inscricao_estadual'] : "";
    var razaoTransp = dadosTransportadora['razao_social'] ? dadosTransportadora['razao_social'] : "";
    var fantasiaTransp = dadosTransportadora['estabelecimento']['nome_fantasia'] ? dadosTransportadora['estabelecimento']['nome_fantasia'] : razaoTransp;
    var cepTransp = dadosTransportadora['estabelecimento']['cep'] ? dadosTransportadora['estabelecimento']['cep'].replace('-', '').replace('.', '') : "";
    var enderecoTransp = dadosTransportadora['estabelecimento']['logradouro'] ? dadosTransportadora['estabelecimento']['logradouro'] : "";
    var numeroEnderecoTransp = dadosTransportadora['estabelecimento']['numero'] ? dadosTransportadora['estabelecimento']['numero'] : "";
    var complementoTransp = dadosTransportadora['estabelecimento']['complemento'] ? dadosTransportadora['estabelecimento']['complemento'] : "";
    var emailTransp = dadosTransportadora['estabelecimento']['email'] ? dadosTransportadora['estabelecimento']['email'] : "";
    var tel1Transp = dadosTransportadora['estabelecimento']['ddd1'] + dadosTransportadora['estabelecimento']['telefone1'] ? dadosTransportadora['estabelecimento']['ddd1'] + dadosTransportadora['estabelecimento']['telefone1'] : "";

    $("#inscestadualtransp").val(inscricaoEstadualTransp)
    $("#razaotransp").val(razaoTransp)
    $("#fantasiatransp").val(fantasiaTransp)
    $("#ceptransp").val(cepTransp)
    $("#enderecotransp").val(enderecoTransp)
    $("#numeroendtransp").val(numeroEnderecoTransp)
    $("#complementoendtransp").val(complementoTransp)
    $("#emailtransp").val(emailTransp)
    $("#tel1transp").val(tel1Transp)

    PreencheEnderecoComCepTransportadora($("#ceptransp").val().replace(/\D/g, ""));

    return true

  } else {
    console.log(dadosAlternativosTransp.api)

    emailTransp = dadosAlternativosTransp.data.email ? dadosAlternativosTransp.data.email : "";
    cepTransp = dadosAlternativosTransp.data.cep ? dadosAlternativosTransp.data.cep.replace(/\D/g, "") : "";
    enderecoTransp = dadosAlternativosTransp.data.logradouro ? dadosAlternativosTransp.data.logradouro : "";
    numeroEnderecoTransp = dadosAlternativosTransp.data.numero ? dadosAlternativosTransp.data.numero : "";
    complementoTransp = dadosAlternativosTransp.data.complemento ? dadosAlternativosTransp.data.complemento : "";

    if (dadosAlternativosTransp.api == "receitaws") {
      razaoTransp = dadosAlternativosTransp.data.nome ? dadosAlternativosTransp.data.nome : "";
      fantasiaTransp = dadosAlternativosTransp.data.fantasia ? dadosAlternativosTransp.data.fantasia : razaoTransp;
      tel1Transp = dadosAlternativosTransp.data.telefone ? (dadosAlternativosTransp.data.telefone.split('/'))[0].replace(/\D/g, "") : "";

    } else {
      razaoTransp = dadosAlternativosTransp.data["razao_social"] ? dadosAlternativosTransp.data["razao_social"] : "";
      fantasiaTransp = dadosAlternativosTransp.data["nome_fantasia"] ? dadosAlternativosTransp.data["nome_fantasia"] : razaoTransp;
      tel1Transp = dadosAlternativosTransp.data["ddd_telefone"] ? dadosAlternativosTransp.data["ddd_telefone"].replace(/\D/g, "") : "";

    }

    $("#razaotransp").val(razaoTransp);
    $("#fantasiatransp").val(fantasiaTransp);
    $("#ceptransp").val(cepTransp);
    $("#enderecotransp").val(enderecoTransp);
    $("#numeroendtransp").val(numeroEnderecoTransp);
    $("#complementoendtransp").val(complementoTransp);
    $("#emailtransp").val(emailTransp);
    $("#tel1transp").val(tel1Transp);

    PreencheEnderecoComCepTransportadora($("#cepTransp").val().replace(/\D/g, ""))

    return true;
  }
}

function modal_Preenchimento_CNPJ_Transp(cnpjtransp) {
  var cnpjTransportadoraFormatado = cnpjtransp ? cnpjtransp.replace(/\D/g, "") : "";

  Swal.fire({
    title: 'Deseja Autocompletar ou Atualizar as Informações desta Transportadora Automaticamente!',
    showCancelButton: true,
    confirmButtonColor: '#3085d6',
    cancelButtonColor: '#d33',
    confirmButtonText: 'Sim',
    cancelButtonText: 'Não'
  }).then(async (result) => {

    if (result.value == true & cnpjTransportadoraFormatado !== "" & cnpjTransportadoraFormatado.length == 14) {
      let dadosTranspAPI = await fetchApiCnpjVerificaExistencia(cnpjTransportadoraFormatado);
      let status = dadosTranspAPI.status;
      var dadosAlternativosTransp = dadosTranspAPI;

      if (status === 200) {

        Swal.fire({
          title: "Carregando os dados do CNPJ... Por favor aguarde!",
          type: "info",
          allowOutsideClick: false,
          allowEscapeKey: false,
          timer: 180000,
          onOpen: async function () {

            Swal.showLoading()

            let status_preenchimento = await preencheDadosTransportadoraComAPI(cnpjTransportadoraFormatado, dadosAlternativosTransp);

            if (status_preenchimento) {

              Swal.fire({
                title: 'Dados Preenchidos com Sucesso!',
                type: 'success',
                timer: 3000
              })
            } else {

              Swal.fire({
                title: 'Erro ao preencher os dados, aguarde 1 minuto e tente novamente ou faça o preenchimento manual!',
                type: 'error'
              })
            }

          }
        }).then((resultTimer) => {

          if (resultTimer.dismiss == 'timer') {
            Swal.fire({
              title: 'Tempo de Carregamento Excedido, Tente Novamente Mais Tarde ou Faça o Preenchimento Manual!',
              type: 'error'
            })
          }
        })

      } else if (status !== 200) {
        Swal.fire({
          title: `${status} ou CNPJ Inválido!`,
          text: `Favor Digitar um CNPJ Válido ou Faça o Preenchimento Manual!`,
          type: 'warning'
        })

      }

    } else if (result.value == true & cnpjTransportadoraFormatado.length < 14 & cnpjTransportadoraFormatado !== '') {
      Swal.fire({
        title: `CNPJ Incompleto! ${14 - cnpjTransportadoraFormatado.length == 1 ? `Falta ${14 - cnpjTransportadoraFormatado.length} Digito, Favor Verificar o CNPJ!` : `Faltam ${14 - cnpjTransportadoraFormatado.length} Digitos, Favor Verificar o CNPJ!`}`,
        type: 'warning'
      })

    } else if (result.value == true & !cnpjTransportadoraFormatado) {
      Swal.fire({
        title: `CNPJ Vazio!`,
        text: `Favor Digitar o CNPJ!`,
        type: 'error'
      })

    }

  })

}

