async function Valida_CNPJ_Cadastro_Transp(cnpjtransp, numacao, dados) {

  let dadosObj = await fetchApiCnpjVerificaExistencia(cnpjtransp)
  let status = await dadosObj.status

  if (status !== 200) {
    Swal.fire({
      title: `CNPJ Inválido!`,
      text: `Favor Digitar um CNPJ Válido!`,
      type: 'warning'
    })
  }

  if (status === 200) {

    if (numacao == 1) {

      ajaxGet("api/compras/transportador.xsjs?CNPJTransportador=" + dados[0]["NUCNPJ"])
        .then((resp) => { Cadastra_Transportadora(resp, dados) })
        .catch((e) => { console.log(e.message) })

    } else {
      ajaxPut("api/compras/transportador.xsjs", dados)
        .then(funcSucessCadTransportador)
        .catch(funcError, (e) => { console.log(e.message + "   PUT") });
    }

    const textdados = JSON.stringify(dados);

    textoFuncao = 'COMPRAS/CADASTRO-EDIÇÃO DE TRANSPORTADORA';

    var dadosCadDeposito = [{

      "IDFUNCIONARIO": IDFuncionarioLogin.toString(),
      "PATHFUNCAO": textoFuncao,
      "DADOS": textdados,
      "IP": ipCliente
    }];

    //ajaxPut("api/log-web.xsjs", dadosCadDeposito)
    //.then(funcSucessLog)
    //.catch(funcErrorLog);

  }

}

function Cadastra_Transportadora(resp, dados) {

  if (resp.rows == 0) {
    ajaxPost("api/compras/transportador.xsjs", dados)
      .then(funcSucessCadTransportador)
      .catch(funcError, (e) => { console.log(e.message) })
  } else {

    funcErrorEmpresa()
  }
}

function funcSucessCadTransportador(resposta) {

  alerta_cadastrado_sucesso();
  $("#Cadtransportador").modal('hide');
  pesq_transportador(1);
}

