async function pesquisarDistribuicoes() {
  try {
    let dtInicial = $('#dtInicioDistribuicao').val();
    let dtFinal = $('#dtFimDistribuicao').val();
    let idDistribuicao = $('#idDistribuicao').val() || "";

    if (dtInicial > dtFinal) {
      return msgWarning('A data Inicial não pode ser maior que a data Final')
    }

    await ajaxGetAllData(`api/compras/dq-distribuicao-compras.xsjs?dpesqini=${dtInicial}&dpesqfin=${dtFinal}&idDist=${idDistribuicao}`, 'Carregando Distribuições, aguarde...')
      .then(retornoPesquisarDistribuicoes)
      .catch((error) => { throw error });
  } catch (error) {
    console.log(error);
    msgError();
  }

}

function retornoPesquisarDistribuicoes(respostaPesquisarDistribuicoes) {
  let dadosTable = [];
  let { data } = respostaPesquisarDistribuicoes;

  if (data?.length) {

    for (let registro of data) {
      let IdDistribuicaoCompra = registro?.IDDISTRIBUICAOCOMPRAS;
      let Observacao = registro?.OBSERVACAO;
      let DataCriacao = registro?.DATACRIACAOFORMATADA;
      let FilialOrigem = registro?.FILIALORIGEM;
      let DsFabricante = registro?.DSFABRICANTE;
      let IdTipoMercadoria = registro?.IDTIPOMERCADORIA;
      let Status = registro?.STATUS === "0" ? 'Salvo' : 'Gerado Vendas';
      let DescMercadoria = "";

      if (IdTipoMercadoria === 1) {
        DescMercadoria = "Roupas e Vestuário";
      } else if (IdTipoMercadoria === 2) {
        DescMercadoria = "Calçados";
      } else if (IdTipoMercadoria === 3) {
        DescMercadoria = "Acessórios";
      }

      let BtnOpcao = `
                <button type="button" class="btn btn-primary btn-xs btn-icon waves-effect waves-themed" title="Editar Distribuição" id="${IdDistribuicaoCompra}" onclick="AdicionarDistribuicao(this.id)">
                    <i class="fal fa-edit"></i>
                </button>
            `;

      dadosTable.push([
        IdDistribuicaoCompra
        , Observacao
        , DataCriacao
        , Status
        , DsFabricante
        , DescMercadoria
        , FilialOrigem
        , BtnOpcao
      ]);
    }

  }

  $('#resultadoListaDistribuicao').html(`
        <div class="page-content p-1">
            <table id="tableListaDistribuicoes" class="table table-bordered table-hover table-responsive-lg table-striped w-100">
            <thead class="bg-primary-600">
                <tr>
                <th style="text-align: center !important" >#</th>
                <th style="text-align: center !important" >Descrição</th>
                <th style="text-align: center !important" >Data</th>
                <th style="text-align: center !important" >Status</th>
                <th style="text-align: center !important" >Fabricante</th>
                <th style="text-align: center !important" >Tipo Mercadoria</th>
                <th style="text-align: center !important" >Filial</th>
                <th style="text-align: center !important" ></th>
                </tr>
            </thead>
            <tbody></tbody>
            </table>
        </div>
    `);

  $('#tableListaDistribuicoes').DataTable({
    data: dadosTable,
    language: {
      "emptyTable": 'Não há Distribuições',
    },
    pageLength: 50,
    paging: true,
    searching: true,
    deferRender: true,
    responsive: true,
    columnDefs: [
      {
        targets: [0, 1, 4, 5, 6],
        className: 'td-text-left'
      },
      {
        targets: [2, 3],
        className: 'td-text-center'
      },
      {
        targets: [7],
        orderable: false,
        className: 'td-text-center'
      },
    ],
    initComplete: function ({ nTable, aoData }) {
      let idTable = `#${nTable.id}`;

      if (aoData?.length > 0) {
        $(idTable).focus();

        $('html, body').animate({
          scrollTop: $(idTable).offset().top
        }, 1000);
      }
    }
  })
}

